"use client";

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Search, Trophy, Home, List, Users, 
  ChevronRight, Crown, Activity, 
  ChevronLeft, Copy, Shield, X, Swords, Crosshair,
  Zap, Anchor, Target, Flame, BoxSelect, ShieldAlert,
  Terminal, Cpu, Globe, Radio, Lock, Unlock, Eye, Save, Trash2,
  Ban, MessageSquare, HardDrive, BarChart3, AlertTriangle, UserMinus,
  Megaphone, Send, Wifi, Clock, Fingerprint, Layers, ExternalLink
} from 'lucide-react';
import playersData from '../data/players.json';

export default function NordenApexDashboard() {
  // --- CORE SYSTEM STATE ---
  const [currentView, setCurrentView] = useState("Rankings");
  const [activeTab, setActiveTab] = useState("Overall");
  const [search, setSearch] = useState("");
  const [isExpanded, setIsExpanded] = useState(false);
  const [copied, setCopied] = useState(false);
  const [selectedPlayer, setSelectedPlayer] = useState<any | null>(null);
  const [mounted, setMounted] = useState(false);

  // --- STAFF & ADMIN STATE ---
  const [isStaffLoggedIn, setIsStaffLoggedIn] = useState(false);
  const [accessKey, setAccessKey] = useState("");
  const [authError, setAuthError] = useState(false);
  const [adminTab, setAdminTab] = useState("Overview"); 
  const [broadcastMsg, setBroadcastMsg] = useState("");
  const [isBroadcasting, setIsBroadcasting] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  const kitTabs = ["Overall", "Crystal", "Sword", "UHC", "Axe", "Neth Pot", "SMP", "Tank", "Anchor", "Boxing"];

  const handleCopy = () => {
    navigator.clipboard.writeText("play.nordenmc.com");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleStaffLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (accessKey === "NORDEN_2026") {
      setIsStaffLoggedIn(true);
      setAuthError(false);
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  const getTierStyles = (tier: string) => {
    const t = tier?.toUpperCase() || "";
    if (t.includes('HT1')) return 'text-red-500 border-red-500/50 bg-red-500/10 shadow-[0_0_40px_rgba(239,68,68,0.4)] ring-1 ring-red-500/30';
    if (t.includes('LT1')) return 'text-cyan-400 border-cyan-500/50 bg-cyan-500/10 shadow-[0_0_40px_rgba(6,182,212,0.4)] ring-1 ring-cyan-500/30';
    if (t.includes('T2')) return 'text-purple-400 border-purple-500/40 bg-purple-500/10 shadow-[0_0_30px_rgba(168,85,247,0.3)]';
    return 'text-gray-400 border-white/10 bg-white/5';
  };

  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data
      .filter((p: any) => {
        const nameMatch = p.name?.toLowerCase().includes(search.toLowerCase());
        const tabMatch = activeTab === "Overall" || p.kit === activeTab;
        return nameMatch && tabMatch;
      })
      .sort((a: any, b: any) => (a.rank || 99) - (b.rank || 99));
  }, [search, activeTab]);

  if (!mounted) return null;

  return (
    <div className="flex min-h-screen bg-[#020204] text-[#e1e1e3] font-sans selection:bg-cyan-500/40 overflow-hidden">
      
      {/* --- SIDEBAR: THE COMMAND RAIL --- */}
      <aside className={`flex flex-col py-12 border-r border-white/5 bg-[#050508] transition-all duration-700 cubic-bezier(0.16, 1, 0.3, 1) z-[100] relative ${isExpanded ? 'w-80 px-8' : 'w-24 items-center'}`}>
        <div onClick={() => setIsExpanded(!isExpanded)} className="mb-16 cursor-pointer text-cyan-500 bg-cyan-500/10 p-5 rounded-[2rem] border border-cyan-500/20 hover:shadow-[0_0_50px_rgba(6,182,212,0.4)] hover:scale-110 transition-all active:scale-95">
          {isExpanded ? <ChevronLeft size={32} /> : <Fingerprint size={32} />}
        </div>
        
        <nav className="flex flex-col gap-8 w-full">
          {[
            { id: "Home", icon: <Home size={26} />, label: "Nexus Hub" },
            { id: "Rankings", icon: <List size={26} />, label: "Global Standings" },
            { id: "Staff", icon: <ShieldAlert size={26} />, label: "Command Center" },
            { id: "Community", icon: <MessageSquare size={26} />, label: "Staff Uplink" }
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setCurrentView(item.id)}
              className={`flex items-center gap-6 p-5 rounded-[1.5rem] transition-all duration-500 group relative ${currentView === item.id ? 'bg-cyan-500/10 text-cyan-400 border border-white/5 shadow-inner' : 'text-gray-600 hover:text-gray-300'}`}
            >
              <div className={`transition-transform duration-500 ${currentView === item.id ? 'scale-110 drop-shadow-[0_0_12px_rgba(6,182,212,0.8)]' : 'group-hover:scale-110'}`}>
                {item.icon}
              </div>
              {isExpanded && <span className="font-black uppercase tracking-[0.3em] text-[10px] whitespace-nowrap">{item.label}</span>}
              {currentView === item.id && <div className="absolute right-0 w-2 h-8 bg-cyan-500 rounded-l-full shadow-[0_0_30px_#22d3ee]"></div>}
            </button>
          ))}
        </nav>
      </aside>

      {/* --- MAIN CORE --- */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto custom-scrollbar relative">
        
        {/* GLOBAL BROADCAST SYSTEM */}
        {isBroadcasting && (
          <div className="bg-cyan-500 text-black py-4 px-12 flex items-center justify-between animate-in slide-in-from-top-full duration-700 sticky top-0 z-[200] shadow-[0_10px_50px_rgba(6,182,212,0.4)]">
             <div className="flex items-center gap-5 font-black italic uppercase tracking-tighter text-lg">
                <Megaphone className="animate-bounce" size={24} /> 
                <span className="tracking-widest underline decoration-2 underline-offset-4">ALERT:</span> {broadcastMsg}
             </div>
             <button onClick={() => setIsBroadcasting(false)} className="hover:rotate-90 transition-transform"><X size={24} /></button>
          </div>
        )}

        {/* NAVIGATION HEADER */}
        <header className="bg-[#050508]/60 backdrop-blur-2xl border-b border-white/5 py-6 px-14 flex items-center justify-between sticky top-0 z-[150]">
          <div className="flex items-center gap-8">
            <h1 className="text-3xl font-black italic tracking-tighter text-white uppercase group cursor-default">
              Norden<span className="text-cyan-500 group-hover:shadow-[0_0_20px_#22d3ee] transition-all">MC</span>
            </h1>
            <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-[0.5em] text-cyan-400/40 px-6 py-2 bg-white/[0.02] border border-white/5 rounded-full">
               <Radio size={14} className="animate-pulse" /> Uplink: 04-Nexus-Live
            </div>
          </div>
          
          <div className="flex items-center gap-10">
            <div className="relative group hidden lg:block">
               <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-700 group-focus-within:text-cyan-500 transition-colors" size={18} />
               <input 
                 type="text" 
                 placeholder="Search Player Database..." 
                 className="bg-white/[0.03] border border-white/5 rounded-2xl py-3 pl-14 pr-8 outline-none focus:border-cyan-500/30 transition-all text-[11px] font-black uppercase tracking-[0.2em] w-80 text-white placeholder:opacity-30"
                 value={search}
                 onChange={(e) => setSearch(e.target.value)}
               />
            </div>
            <button onClick={handleCopy} className="text-[11px] font-black uppercase tracking-[0.3em] bg-cyan-500 text-black px-8 py-3 rounded-2xl shadow-[0_0_40px_rgba(6,182,212,0.3)] hover:scale-105 active:scale-95 transition-all">
              {copied ? "COPIED!" : "PLAY.NORDENMC.COM"}
            </button>
          </div>
        </header>

        {/* --- DYNAMIC VIEWPORT --- */}
        <main className="p-16 max-w-[1600px] mx-auto w-full animate-in fade-in slide-in-from-bottom-6 duration-1000">
          
          {/* VIEW: STAFF/ADMIN PANEL */}
          {currentView === "Staff" && (
            <div className="animate-in fade-in zoom-in duration-700">
              {!isStaffLoggedIn ? (
                /* LOGIN SCREEN */
                <div className="flex flex-col items-center justify-center min-h-[60vh]">
                   <div className={`bg-[#0a0a0d] border ${authError ? 'border-red-500 shadow-[0_0_60px_rgba(239,68,68,0.2)]' : 'border-white/5'} p-20 rounded-[5rem] w-full max-w-xl text-center relative overflow-hidden transition-all duration-500`}>
                      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500/40 to-transparent"></div>
                      <div className="w-28 h-28 bg-white/[0.03] rounded-full flex items-center justify-center mx-auto mb-10 border border-white/5 shadow-2xl">
                        <Lock size={48} className={authError ? "text-red-500 animate-bounce" : "text-cyan-500"} />
                      </div>
                      <h2 className="text-4xl font-black uppercase italic tracking-tighter mb-4 text-white">Shadow<span className="text-cyan-500">Gate</span></h2>
                      <p className="text-[11px] font-black uppercase tracking-[0.6em] text-gray-700 mb-14">Identity Verification // NordenMC Ops</p>
                      
                      <form onSubmit={handleStaffLogin} className="space-y-6">
                        <input 
                          type="password" 
                          placeholder="••••••••••••" 
                          className="w-full bg-white/[0.02] border border-white/10 rounded-[2rem] py-6 px-8 text-center text-xl font-black tracking-[1.5em] outline-none focus:border-cyan-500/50 transition-all uppercase text-cyan-400 placeholder:opacity-10"
                          value={accessKey}
                          onChange={(e) => setAccessKey(e.target.value)}
                        />
                        <button className="w-full py-6 bg-cyan-500 text-black font-black uppercase tracking-widest rounded-[2rem] hover:bg-cyan-400 transition-all shadow-[0_20px_50px_rgba(6,182,212,0.3)] flex items-center justify-center gap-4 text-sm group">
                           Verify Command Credentials <ChevronRight className="group-hover:translate-x-2 transition-transform" />
                        </button>
                      </form>
                   </div>
                </div>
              ) : (
                /* LOGGED IN DASHBOARD */
                <div className="space-y-12 animate-in fade-in duration-1000">
                   <div className="flex justify-between items-center bg-[#0a0a0d] p-4 rounded-[3rem] border border-white/5">
                      <div className="flex gap-4">
                        {["Overview", "Database", "Bans", "Broadcast", "Terminal"].map((tab) => (
                          <button 
                            key={tab} 
                            onClick={() => setAdminTab(tab)}
                            className={`px-10 py-4 rounded-[2rem] text-[11px] font-black uppercase tracking-widest transition-all ${adminTab === tab ? 'bg-cyan-500 text-black shadow-2xl' : 'text-gray-600 hover:text-white hover:bg-white/5'}`}
                          >
                            {tab}
                          </button>
                        ))}
                      </div>
                      <button onClick={() => setIsStaffLoggedIn(false)} className="px-8 py-4 bg-red-500/10 border border-red-500/20 text-red-500 rounded-[2rem] text-[11px] font-black uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all">
                        Log-Off
                      </button>
                   </div>

                   {/* ADMIN TAB: BROADCAST TOOL */}
                   {adminTab === "Broadcast" && (
                     <div className="bg-[#0a0a0d] border border-white/5 p-20 rounded-[5rem] text-center space-y-10 animate-in slide-in-from-bottom-10">
                        <Megaphone size={80} className="text-cyan-500 mx-auto drop-shadow-[0_0_30px_rgba(6,182,212,0.5)]" />
                        <div>
                          <h3 className="text-5xl font-black italic uppercase tracking-tighter text-white mb-4">Network <span className="text-cyan-500">Alert</span></h3>
                          <p className="text-gray-600 font-black uppercase tracking-widest text-[11px] max-w-md mx-auto leading-relaxed">Broadcast an un-skippable priority message to every connected player on the NordenMC server nodes.</p>
                        </div>
                        <div className="max-w-3xl mx-auto flex gap-6">
                           <input 
                             type="text" 
                             placeholder="Type broadcast alert..." 
                             className="flex-1 bg-white/[0.03] border border-white/10 rounded-3xl p-8 text-white font-black uppercase tracking-widest outline-none focus:border-cyan-500 transition-all text-lg"
                             value={broadcastMsg}
                             onChange={(e) => setBroadcastMsg(e.target.value)}
                           />
                           <button onClick={() => setIsBroadcasting(true)} className="px-12 bg-cyan-500 text-black font-black uppercase tracking-widest rounded-3xl shadow-2xl hover:bg-cyan-400 active:scale-95 transition-all">
                             Trigger
                           </button>
                        </div>
                     </div>
                   )}

                   {/* ADMIN TAB: OVERVIEW STATS */}
                   {adminTab === "Overview" && (
                     <div className="grid grid-cols-1 md:grid-cols-4 gap-10 animate-in fade-in duration-700">
                        {[
                          { l: "Server TPS", v: "20.0", c: "text-green-400", i: <Activity /> },
                          { l: "Network Load", v: "4.2ms", c: "text-cyan-400", i: <Radio /> },
                          { l: "Online Count", v: "142", c: "text-purple-400", i: <Users /> },
                          { l: "Open Cases", v: "03", c: "text-orange-400", i: <AlertTriangle /> }
                        ].map(s => (
                          <div key={s.l} className="bg-[#0a0a0d] border border-white/5 p-12 rounded-[4rem] relative overflow-hidden group hover:border-cyan-500/40 transition-all">
                             <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:opacity-20 transition-opacity scale-[3]">{s.i}</div>
                             <p className="text-[10px] font-black text-gray-700 uppercase tracking-[0.5em] mb-4">{s.l}</p>
                             <p className={`text-5xl font-black italic tracking-tighter ${s.c}`}>{s.v}</p>
                          </div>
                        ))}
                     </div>
                   )}

                   {/* ADMIN TAB: TERMINAL */}
                   {adminTab === "Terminal" && (
                     <div className="bg-[#020205] border border-white/10 rounded-[4rem] h-[650px] overflow-hidden flex flex-col font-mono shadow-2xl">
                        <div className="bg-white/[0.03] p-6 border-b border-white/5 flex items-center gap-3">
                           <div className="w-3 h-3 rounded-full bg-red-500/50"></div>
                           <div className="w-3 h-3 rounded-full bg-yellow-500/50"></div>
                           <div className="w-3 h-3 rounded-full bg-green-500/50"></div>
                           <span className="ml-6 text-[11px] font-black uppercase tracking-widest text-gray-600">Norden_Nexus_Terminal_V4.2</span>
                        </div>
                        <div className="flex-1 p-12 text-sm text-cyan-500/80 space-y-3 overflow-y-auto custom-scrollbar">
                           <p className="text-gray-700">[14:22:10] Initialize NordenMC core daemon...</p>
                           <p className="text-cyan-400">[14:22:12] Cloud uplink established: Norden-Nexus-01 (US-East)</p>
                           <p className="text-white font-bold">[14:23:01] Admin UtkarshP session authorized.</p>
                           <p className="text-gray-700">[14:24:50] Scanning network nodes...</p>
                           <p className="text-green-500 font-bold">[14:25:00] All nodes operating at 100% efficiency.</p>
                           <p className="text-orange-500">[14:28:30] Warning: Latency spike on node 03.</p>
                           <p className="animate-pulse">_</p>
                        </div>
                        <div className="p-8 bg-white/[0.01] border-t border-white/5 flex gap-6 items-center">
                           <Terminal className="text-cyan-500" size={24} />
                           <input type="text" placeholder="SEND ROOT COMMAND..." className="bg-transparent border-none outline-none w-full text-white text-sm uppercase tracking-widest placeholder:opacity-10" />
                        </div>
                     </div>
                   )}
                </div>
              )}
            </div>
          )}

          {/* VIEW: GLOBAL RANKINGS */}
          {currentView === "Rankings" && (
            <div className="space-y-20 animate-in fade-in slide-in-from-bottom-8 duration-1000">
              
              {/* TOP 3 PODIUM */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
                {filteredPlayers.slice(0, 3).map((p, i) => (
                  <div key={p.name} onClick={() => setSelectedPlayer(p)} className="relative group cursor-pointer h-full">
                    <div className={`absolute inset-0 blur-[100px] opacity-0 group-hover:opacity-20 transition-opacity duration-1000 ${i === 0 ? 'bg-yellow-500' : 'bg-cyan-500'}`}></div>
                    <div className="bg-[#0a0a0d] border border-white/5 p-12 rounded-[4.5rem] relative z-10 hover:border-cyan-500/40 hover:-translate-y-6 transition-all duration-700 h-full flex flex-col items-center justify-center text-center">
                       <div className="relative mb-10">
                         <img src={`https://mc-heads.net/avatar/${p.name}/150`} className="w-36 h-36 rounded-[3rem] border-4 border-[#0a0a0d] shadow-[0_30px_60px_rgba(0,0,0,0.8)] group-hover:rotate-6 transition-transform duration-700" alt="" />
                         <div className={`absolute -top-6 -right-6 p-4 rounded-3xl border border-white/10 shadow-2xl ${i === 0 ? 'bg-yellow-500 text-black' : 'bg-[#050508] text-cyan-500'}`}>
                           {i === 0 ? <Crown size={32} /> : <Trophy size={32} />}
                         </div>
                       </div>
                       <div>
                         <h3 className="text-4xl font-black italic uppercase tracking-tighter text-white mb-3 leading-none">{p.name}</h3>
                         <p className="text-[11px] font-black tracking-[0.5em] text-cyan-500 uppercase">Global Legend #{p.rank}</p>
                       </div>
                       <div className={`mt-8 px-10 py-3 rounded-2xl font-black italic text-3xl shadow-xl ${getTierStyles(p.tier)}`}>
                         {p.tier}
                       </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* LIST FILTER */}
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-10 border-b border-white/5 pb-10">
                 <div className="flex flex-wrap gap-4">
                    {kitTabs.map(tab => (
                      <button 
                        key={tab} 
                        onClick={() => setActiveTab(tab)}
                        className={`px-8 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all border ${activeTab === tab ? 'bg-white text-black border-white shadow-[0_0_30px_rgba(255,255,255,0.2)] scale-105' : 'text-gray-600 border-white/5 hover:border-white/20 hover:text-white hover:bg-white/5'}`}
                      >
                        {tab}
                      </button>
                    ))}
                 </div>
              </div>

              {/* MASTER PLAYER LIST */}
              <div className="space-y-6">
                {filteredPlayers.map((player: any) => (
                  <div 
                    key={player.name} 
                    onClick={() => setSelectedPlayer(player)}
                    className="grid grid-cols-12 gap-8 p-10 items-center bg-[#0a0a0d] border border-white/[0.03] rounded-[3.5rem] hover:bg-white/[0.01] hover:border-cyan-500/30 transition-all duration-700 group cursor-pointer relative overflow-hidden"
                  >
                    <div className="absolute inset-0 bg-gradient-to-r from-cyan-500/0 via-cyan-500/[0.02] to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    <div className="col-span-1 text-6xl font-black italic text-gray-900 group-hover:text-cyan-500/20 transition-all pl-4">
                      {player.rank.toString().padStart(2, '0')}
                    </div>
                    <div className="col-span-7 flex items-center gap-10 relative z-10">
                      <img src={`https://mc-heads.net/avatar/${player.name}/120`} className="w-20 h-20 rounded-[1.8rem] border border-white/10 group-hover:scale-110 group-hover:rotate-2 transition-all duration-700 shadow-2xl" alt="" />
                      <div>
                        <div className="font-black text-3xl text-white uppercase italic tracking-tighter flex items-center gap-6">
                          {player.name} 
                          <span className="text-[10px] not-italic font-black bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 px-5 py-1.5 rounded-xl uppercase tracking-widest">Contender</span>
                        </div>
                        <div className="flex items-center gap-6 mt-3 text-[11px] font-black uppercase tracking-widest text-gray-700 group-hover:text-gray-500 transition-colors">
                           <Activity size={16} className="text-cyan-500/50" /> {player.kit} Discipline
                           <div className="w-1.5 h-1.5 rounded-full bg-cyan-500/20"></div>
                           <span>Active Database Entry</span>
                        </div>
                      </div>
                    </div>
                    <div className="col-span-4 flex justify-end items-center gap-14 pr-8 relative z-10">
                       <div className={`px-12 py-4 rounded-[1.5rem] font-black italic text-3xl tracking-tighter transition-all duration-700 group-hover:scale-110 group-hover:shadow-[0_0_50px_rgba(34,211,238,0.2)] ${getTierStyles(player.tier)}`}>
                         {player.tier}
                       </div>
                       <div className="w-16 h-16 rounded-[1.5rem] border border-white/10 flex items-center justify-center text-gray-800 group-hover:bg-cyan-500 group-hover:text-black group-hover:border-cyan-500 transition-all">
                          <ChevronRight size={32} />
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* VIEW: HOME PORTAL */}
          {currentView === "Home" && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 animate-in fade-in slide-in-from-left-10 duration-1000">
               <div className="bg-[#0a0a0d] border border-white/5 p-16 rounded-[5rem] space-y-10 relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-16 opacity-5 group-hover:opacity-10 transition-opacity">
                    <Globe size={300} />
                  </div>
                  <Globe size={60} className="text-cyan-500" />
                  <h2 className="text-6xl font-black italic uppercase tracking-tighter text-white leading-none">Nexus<br/><span className="text-cyan-500">Architecture</span></h2>
                  <p className="text-gray-600 font-bold uppercase tracking-[0.2em] text-sm leading-loose max-w-xl">
                    Welcome to the decentralized command hub for NordenMC. Monitor competitive tier rankings, manage staff protocols, and access regional uplink nodes in real-time.
                  </p>
                  <div className="flex gap-4 pt-10 border-t border-white/5">
                     <div className="p-8 bg-white/[0.02] border border-white/5 rounded-[2.5rem] flex-1">
                        <p className="text-[10px] font-black text-gray-700 uppercase mb-3">Live Players</p>
                        <p className="text-3xl font-black text-white italic">1.4k+</p>
                     </div>
                     <div className="p-8 bg-white/[0.02] border border-white/5 rounded-[2.5rem] flex-1">
                        <p className="text-[10px] font-black text-gray-700 uppercase mb-3">Ping Latency</p>
                        <p className="text-3xl font-black text-cyan-500 italic">08ms</p>
                     </div>
                  </div>
               </div>
               <div className="bg-gradient-to-br from-[#0a0a0d] to-cyan-950/20 border border-white/5 p-16 rounded-[5rem] flex flex-col justify-end text-right relative group">
                  <Layers size={100} className="text-cyan-500/10 absolute top-16 left-16 group-hover:scale-110 transition-transform" />
                  <h3 className="text-7xl font-black italic uppercase tracking-tighter text-white leading-[0.8]">Apex<br/><span className="text-cyan-500 text-8xl">System</span></h3>
                  <p className="text-[11px] font-black uppercase tracking-[0.8em] text-cyan-500/30 mt-12">Build V6.0.42 // NordenMC Core</p>
               </div>
            </div>
          )}

        </main>
      </div>

      {/* --- HYPER-GUI PLAYER MODAL --- */}
      {selectedPlayer && (
        <div className="fixed inset-0 bg-black/98 backdrop-blur-[60px] z-[500] flex items-center justify-center p-12 animate-in fade-in duration-500" onClick={() => setSelectedPlayer(null)}>
           <div className="bg-[#050508] border border-white/10 rounded-[5rem] w-full max-w-6xl overflow-hidden relative shadow-[0_50px_200px_rgba(0,0,0,1)] animate-in zoom-in-95 duration-500" onClick={e => e.stopPropagation()}>
              
              {/* TOP ACCENT LINE */}
              <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-transparent via-cyan-500 to-transparent shadow-[0_0_40px_rgba(6,182,212,0.8)]"></div>
              
              <div className="grid grid-cols-12 h-[750px]">
                 {/* LEFT: IDENTITY PLATE */}
                 <div className="col-span-5 bg-white/[0.02] border-r border-white/5 p-20 flex flex-col items-center justify-center text-center">
                    <div className="relative mb-14">
                       <div className="absolute inset-0 bg-cyan-500 blur-[120px] rounded-full opacity-20 animate-pulse"></div>
                       <img src={`https://mc-heads.net/avatar/${selectedPlayer.name}/250`} className="w-56 h-56 rounded-[4rem] relative z-10 border-4 border-[#050508] shadow-[0_40px_80px_rgba(0,0,0,0.8)]" alt="" />
                    </div>
                    <h2 className="text-6xl font-black italic tracking-tighter uppercase text-white mb-6 leading-none">{selectedPlayer.name}</h2>
                    <div className={`px-14 py-5 rounded-[2rem] font-black italic text-4xl tracking-tighter shadow-2xl ${getTierStyles(selectedPlayer.tier)}`}>
                       {selectedPlayer.tier}
                    </div>
                    <p className="text-[11px] font-black uppercase tracking-[0.6em] text-gray-700 mt-10 italic">NordenMC Database Verified</p>
                 </div>

                 {/* RIGHT: DATA TERMINAL */}
                 <div className="col-span-7 p-24 relative flex flex-col justify-center">
                    <button onClick={() => setSelectedPlayer(null)} className="absolute top-14 right-14 text-gray-700 hover:text-white transition-all hover:scale-125"><X size={40} /></button>
                    
                    <div className="space-y-16">
                       <div>
                          <p className="text-[11px] font-black uppercase tracking-[0.6em] text-cyan-500 mb-8 flex items-center gap-4">
                             <Crosshair size={18} /> Identity Scan Result
                          </p>
                          <div className="grid grid-cols-2 gap-14">
                             <div>
                                <p className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-600 mb-3">Global Ranking</p>
                                <p className="text-5xl font-black italic text-white tracking-tighter">#{selectedPlayer.rank}</p>
                             </div>
                             <div>
                                <p className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-600 mb-3">Main Kit Spec</p>
                                <p className="text-5xl font-black italic text-white tracking-tighter">{selectedPlayer.kit || "Universal"}</p>
                             </div>
                          </div>
                       </div>

                       <div>
                          <div className="flex justify-between items-center mb-5">
                            <p className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-500 italic">Combat Proficiency Output</p>
                            <span className="text-cyan-400 font-black italic text-sm">94.8% SYNC</span>
                          </div>
                          <div className="h-4 w-full bg-white/[0.03] rounded-full border border-white/5 p-1 relative">
                             <div className="h-full bg-gradient-to-r from-cyan-600 to-cyan-400 rounded-full shadow-[0_0_30px_#22d3ee] animate-in slide-in-from-left duration-1000" style={{ width: '94.8%' }}></div>
                          </div>
                       </div>

                       <div className="pt-14 border-t border-white/5 grid grid-cols-3 gap-10">
                          {['Versatility', 'Efficiency', 'Stamina'].map(stat => (
                             <div key={stat} className="text-center group/stat">
                                <p className="text-[10px] font-black uppercase text-gray-700 mb-3 tracking-[0.3em] group-hover/stat:text-cyan-500 transition-colors">{stat}</p>
                                <div className="text-2xl font-black italic text-white tracking-tighter">9.8/10</div>
                             </div>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* BACKGROUND DECORATIVE FX */}
      <div className="fixed top-0 right-0 w-[1000px] h-[1000px] bg-cyan-600/[0.03] blur-[200px] rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none z-0"></div>
      <div className="fixed bottom-0 left-0 w-[800px] h-[800px] bg-purple-600/[0.02] blur-[200px] rounded-full translate-y-1/2 -translate-x-1/2 pointer-events-none z-0"></div>
    </div>
  );
}